/**
 * Tests that the QueryJoinOptimizer does not choose a merge join when variables of the join arguments will already be
 * bound at runtime (by an enclosing OPTIONAL, LATERAL or BIND), since a merge join evaluates both arguments as ordered
 * scans without pushing the runtime bindings into the right argument, whereas an indexed nested loop join would.
 */
public class QueryJoinOptimizerMergeJoinBoundVarsTest {

	@Test
	public void mergeJoinDisabledInOptionalWhenOuterVarBound() {
		QueryRoot root = optimize("SELECT * WHERE {\n"
				+ "  ?x <urn:knows> ?s .\n"
				+ "  OPTIONAL {\n"
				+ "    ?s <urn:p> ?o .\n"
				+ "    ?o <urn:q> ?v .\n"
				+ "  }\n"
				+ "}");

		Join join = findJoinByArgPredicates(root, "urn:p", "urn:q");
		assertThat(join.isMergeJoin())
				.as("?s is bound at runtime by the OPTIONAL's left arg, so a merge join must not be used")
				.isFalse();
	}

	@Test
	public void mergeJoinDisabledInLateralWhenOuterVarBound() {
		QueryRoot root = optimize("SELECT * WHERE {\n"
				+ "  ?x <urn:knows> ?s .\n"
				+ "  LATERAL {\n"
				+ "    ?s <urn:p> ?o .\n"
				+ "    ?o <urn:q> ?v .\n"
				+ "  }\n"
				+ "}");

		Join join = findJoinByArgPredicates(root, "urn:p", "urn:q");
		assertThat(join.isMergeJoin())
				.as("?s is bound at runtime by the LATERAL's left arg, so a merge join must not be used")
				.isFalse();
	}

	@Test
	public void crossJoinMergeJoinDisabledWhenOuterVarBound() {
		QueryRoot root = optimize("SELECT * WHERE {\n"
				+ "  ?x <urn:knows> ?s .\n"
				+ "  ?x <urn:likes> ?t .\n"
				+ "  OPTIONAL {\n"
				+ "    ?s <urn:p1> \"l1\" .\n"
				+ "    ?t <urn:q> ?o .\n"
				+ "    ?o <urn:r> ?v .\n"
				+ "  }\n"
				+ "}");

		Join join = findJoinByArgPredicates(root, "urn:q", "urn:r");
		assertThat(join.isMergeJoin())
				.as("?t is bound at runtime by the OPTIONAL's left arg, so a merge join must not be used even though "
						+ "the join is a cross join with respect to its sibling join args")
				.isFalse();
	}

	@Test
	public void crossJoinMergeJoinDisabledWhenBindBoundVar() {
		QueryRoot root = optimize("SELECT * WHERE {\n"
				+ "  BIND(<urn:t1> AS ?t)\n"
				+ "  ?s <urn:p1> \"l1\" .\n"
				+ "  ?s <urn:p2> ?a .\n"
				+ "  ?t <urn:q> ?o .\n"
				+ "  ?o <urn:r> ?v .\n"
				+ "}");

		Join join = findJoinByArgPredicates(root, "urn:q", "urn:r");
		assertThat(join.isMergeJoin())
				.as("?t is bound at runtime by the BIND that is evaluated first, so a merge join must not be used")
				.isFalse();
	}

	@Test
	public void mergeJoinStillEnabledAtTopLevel() {
		QueryRoot root = optimize("SELECT * WHERE {\n"
				+ "  ?a <urn:p> ?b .\n"
				+ "  ?b <urn:q> ?c .\n"
				+ "}");

		Join join = findJoinByArgPredicates(root, "urn:p", "urn:q");
		assertThat(join.isMergeJoin())
				.as("no variables are bound at runtime, so the merge join must remain enabled")
				.isTrue();
		assertThat(join.getOrder().getName()).isEqualTo("b");
	}

	@Test
	public void mergeJoinStillEnabledInOptionalWhenOnlySharedConstant() {
		QueryRoot root = optimize("SELECT * WHERE {\n"
				+ "  ?x <urn:q> ?y .\n"
				+ "  OPTIONAL {\n"
				+ "    ?a <urn:q> ?o .\n"
				+ "    ?o <urn:p> ?v .\n"
				+ "  }\n"
				+ "}");

		Join join = findJoinByArgPredicates(root, "urn:q", "urn:p");
		assertThat(join.isMergeJoin())
				.as("the outer scope only shares an anonymous constant var (the <urn:q> predicate) with the join "
						+ "args, so the merge join must remain enabled")
				.isTrue();
	}

	@Test
	public void crossJoinMergeJoinStillEnabledAtTopLevel() {
		QueryRoot root = optimize("SELECT * WHERE {\n"
				+ "  ?s <urn:p1> ?a .\n"
				+ "  ?a <urn:p2> ?b .\n"
				+ "  ?x <urn:q> ?o .\n"
				+ "  ?o <urn:r> ?y .\n"
				+ "}");

		Join headJoin = findJoinByArgPredicates(root, "urn:p1", "urn:p2");
		assertThat(headJoin.isMergeJoin())
				.as("no variables are bound at runtime, so the merge join for the first join args must remain enabled")
				.isTrue();

		Join tailJoin = findJoinByArgPredicates(root, "urn:q", "urn:r");
		assertThat(tailJoin.isMergeJoin())
				.as("no variables are bound at runtime, so the merge join for the trailing cross join must remain "
						+ "enabled")
				.isTrue();
	}

	private QueryRoot optimize(String query) {
		ParsedQuery parsedQuery = QueryParserUtil.parseQuery(QueryLanguage.SPARQL, query, null);
		QueryRoot root = new QueryRoot(parsedQuery.getTupleExpr());
		new QueryJoinOptimizer(new EvaluationStatistics(), new OrderAwareTripleSource()).optimize(root, null, null);
		return root;
	}

	private Join findJoinByArgPredicates(QueryRoot root, String predicate1, String predicate2) {
		List<Join> joins = new ArrayList<>();
		root.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Join join) {
				joins.add(join);
				super.meet(join);
			}
		});

		for (Join join : joins) {
			String left = predicate(join.getLeftArg());
			String right = predicate(join.getRightArg());
			if (left == null || right == null) {
				continue;
			}
			if (left.equals(predicate1) && right.equals(predicate2)
					|| left.equals(predicate2) && right.equals(predicate1)) {
				return join;
			}
		}

		throw new AssertionError(
				"no join over statement patterns with predicates " + predicate1 + " and " + predicate2 + " in:\n"
						+ root);
	}

	private static String predicate(TupleExpr tupleExpr) {
		if (tupleExpr instanceof StatementPattern statementPattern && statementPattern.getPredicateVar().hasValue()) {
			return statementPattern.getPredicateVar().getValue().stringValue();
		}
		return null;
	}

	private static final class OrderAwareTripleSource extends EmptyTripleSource {

		@Override
		public Set<StatementOrder> getSupportedOrders(Resource subj, IRI pred, Value obj, Resource... contexts) {
			return EnumSet.allOf(StatementOrder.class);
		}
	}
}
